(window.webpackJsonp=window.webpackJsonp||[]).push([[441],{710:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">discount</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">products</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">prices</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> Cashier = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, discount, products, prices</span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.n=n\\n  <span class=\\"hljs-keyword\\">this</span>.customCount=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">this</span>.discount=discount\\n  <span class=\\"hljs-keyword\\">this</span>.productPrice={}\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;products.length;i++){\\n    <span class=\\"hljs-keyword\\">this</span>.productPrice[products[i]]=prices[i]\\n  }\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number[]} product \\n * @param {number[]} amount\\n * @return {number}\\n */</span>\\nCashier.prototype.getBill = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">product, amount</span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.customCount++\\n  <span class=\\"hljs-keyword\\">let</span> isDiscount=<span class=\\"hljs-literal\\">false</span>\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.customCount===<span class=\\"hljs-keyword\\">this</span>.n){\\n    <span class=\\"hljs-keyword\\">this</span>.customCount=<span class=\\"hljs-number\\">0</span>\\n    isDiscount=<span class=\\"hljs-literal\\">true</span>\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> allPrice=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;product.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> prod=product[i]\\n    <span class=\\"hljs-keyword\\">let</span> count=amount[i]\\n    <span class=\\"hljs-keyword\\">let</span> price=<span class=\\"hljs-keyword\\">this</span>.productPrice[prod]\\n    allPrice+=price * count\\n  }\\n  <span class=\\"hljs-keyword\\">if</span>(isDiscount)allPrice=allPrice * (<span class=\\"hljs-number\\">100</span> - <span class=\\"hljs-keyword\\">this</span>.discount) / <span class=\\"hljs-number\\">100</span>\\n  <span class=\\"hljs-keyword\\">return</span> allPrice\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Your Cashier object will be instantiated and called as such:\\n * var obj = new Cashier(n, discount, products, prices)\\n * var param_1 = obj.getBill(product,amount)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"apply-discount-every-n-orders","hasThinking":false,"content":"<p>\u8d85\u5e02\u91cc\u6b63\u5728\u4e3e\u884c\u6253\u6298\u6d3b\u52a8\uff0c\u6bcf\u9694&nbsp;<code>n</code>&nbsp;\u4e2a\u987e\u5ba2\u4f1a\u5f97\u5230 <code>discount</code>&nbsp;\u7684\u6298\u6263\u3002</p>\\n\\n<p>\u8d85\u5e02\u91cc\u6709\u4e00\u4e9b\u5546\u54c1\uff0c\u7b2c&nbsp;<code>i</code>&nbsp;\u79cd\u5546\u54c1\u4e3a&nbsp;<code>products[i]</code>&nbsp;\u4e14\u6bcf\u4ef6\u5355\u54c1\u7684\u4ef7\u683c\u4e3a&nbsp;<code>prices[i]</code>&nbsp;\u3002</p>\\n\\n<p>\u7ed3\u8d26\u7cfb\u7edf\u4f1a\u7edf\u8ba1\u987e\u5ba2\u7684\u6570\u76ee\uff0c\u6bcf\u9694&nbsp;<code>n</code>&nbsp;\u4e2a\u987e\u5ba2\u7ed3\u8d26\u65f6\uff0c\u8be5\u987e\u5ba2\u7684\u8d26\u5355\u90fd\u4f1a\u6253\u6298\uff0c\u6298\u6263\u4e3a&nbsp;<code>discount</code>&nbsp;\uff08\u4e5f\u5c31\u662f\u5982\u679c\u539f\u672c\u8d26\u5355\u4e3a&nbsp;<code>x</code>&nbsp;\uff0c\u90a3\u4e48\u5b9e\u9645\u91d1\u989d\u4f1a\u53d8\u6210&nbsp;<code>x - (discount * x) / 100</code>&nbsp;\uff09\uff0c\u7136\u540e\u7cfb\u7edf\u4f1a\u91cd\u65b0\u5f00\u59cb\u8ba1\u6570\u3002</p>\\n\\n<p>\u987e\u5ba2\u4f1a\u8d2d\u4e70\u4e00\u4e9b\u5546\u54c1\uff0c&nbsp;<code>product[i]</code>&nbsp;\u662f\u987e\u5ba2\u8d2d\u4e70\u7684\u7b2c&nbsp;<code>i</code>&nbsp;\u79cd\u5546\u54c1\uff0c&nbsp;<code>amount[i]</code>&nbsp;\u662f\u5bf9\u5e94\u7684\u8d2d\u4e70\u8be5\u79cd\u5546\u54c1\u7684\u6570\u76ee\u3002</p>\\n\\n<p>\u8bf7\u4f60\u5b9e\u73b0&nbsp;<code>Cashier</code>&nbsp;\u7c7b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>Cashier(int n, int discount, int[] products, int[] prices)</code>&nbsp;\u521d\u59cb\u5316\u5b9e\u4f8b\u5bf9\u8c61\uff0c\u53c2\u6570\u5206\u522b\u4e3a\u6253\u6298\u9891\u7387&nbsp;<code>n</code>&nbsp;\uff0c\u6298\u6263\u5927\u5c0f <code>discount</code>&nbsp;\uff0c\u8d85\u5e02\u91cc\u7684\u5546\u54c1\u5217\u8868 <code>products</code>&nbsp;\u548c\u5b83\u4eec\u7684\u4ef7\u683c <code>prices</code>&nbsp;\u3002</li>\\n\\t<li><code>double&nbsp;getBill(int[] product, int[] amount)</code>&nbsp;\u8fd4\u56de\u8d26\u5355\u7684\u5b9e\u9645\u91d1\u989d\uff08\u5982\u679c\u6709\u6253\u6298\uff0c\u8bf7\u8fd4\u56de\u6253\u6298\u540e\u7684\u7ed3\u679c\uff09\u3002\u8fd4\u56de\u7ed3\u679c\u4e0e\u6807\u51c6\u7b54\u6848\u8bef\u5dee\u5728&nbsp;<code>10^-5</code>&nbsp;\u4ee5\u5185\u90fd\u89c6\u4e3a\u6b63\u786e\u7ed3\u679c\u3002</li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165</strong>\\n[&quot;Cashier&quot;,&quot;getBill&quot;,&quot;getBill&quot;,&quot;getBill&quot;,&quot;getBill&quot;,&quot;getBill&quot;,&quot;getBill&quot;,&quot;getBill&quot;]\\n[[3,50,[1,2,3,4,5,6,7],[100,200,300,400,300,200,100]],[[1,2],[1,2]],[[3,7],[10,10]],[[1,2,3,4,5,6,7],[1,1,1,1,1,1,1]],[[4],[10]],[[7,3],[10,10]],[[7,5,3,1,6,4,2],[10,10,10,9,9,9,7]],[[2,3,5],[5,3,2]]]\\n<strong>\u8f93\u51fa</strong>\\n[null,500.0,4000.0,800.0,4000.0,4000.0,7350.0,2500.0]\\n<strong>\u89e3\u91ca</strong>\\nCashier cashier = new Cashier(3,50,[1,2,3,4,5,6,7],[100,200,300,400,300,200,100]);\\ncashier.getBill([1,2],[1,2]);                        // \u8fd4\u56de 500.0, \u8d26\u5355\u91d1\u989d\u4e3a = 1 * 100 + 2 * 200 = 500.\\ncashier.getBill([3,7],[10,10]);                      // \u8fd4\u56de 4000.0\\ncashier.getBill([1,2,3,4,5,6,7],[1,1,1,1,1,1,1]);    // \u8fd4\u56de 800.0 \uff0c\u8d26\u5355\u539f\u672c\u4e3a 1600.0 \uff0c\u4f46\u7531\u4e8e\u8be5\u987e\u5ba2\u662f\u7b2c\u4e09\u4f4d\u987e\u5ba2\uff0c\u4ed6\u5c06\u5f97\u5230 50% \u7684\u6298\u6263\uff0c\u6240\u4ee5\u5b9e\u9645\u91d1\u989d\u4e3a 1600 - 1600 * (50 / 100) = 800 \u3002\\ncashier.getBill([4],[10]);                           // \u8fd4\u56de 4000.0\\ncashier.getBill([7,3],[10,10]);                      // \u8fd4\u56de 4000.0\\ncashier.getBill([7,5,3,1,6,4,2],[10,10,10,9,9,9,7]); // \u8fd4\u56de 7350.0 \uff0c\u8d26\u5355\u539f\u672c\u4e3a 14700.0 \uff0c\u4f46\u7531\u4e8e\u7cfb\u7edf\u8ba1\u6570\u518d\u6b21\u8fbe\u5230\u4e09\uff0c\u8be5\u987e\u5ba2\u5c06\u5f97\u5230 50% \u7684\u6298\u6263\uff0c\u5b9e\u9645\u91d1\u989d\u4e3a 7350.0 \u3002\\ncashier.getBill([2,3,5],[5,3,2]);                    // \u8fd4\u56de 2500.0\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n &lt;= 10^4</code></li>\\n\\t<li><code>0 &lt;= discount &lt;= 100</code></li>\\n\\t<li><code>1 &lt;= products.length &lt;= 200</code></li>\\n\\t<li><code>1 &lt;= products[i] &lt;= 200</code></li>\\n\\t<li><code>products</code>&nbsp;\u5217\u8868\u4e2d&nbsp;<strong>\u4e0d\u4f1a</strong>&nbsp;\u6709\u91cd\u590d\u7684\u5143\u7d20\u3002</li>\\n\\t<li><code>prices.length == products.length</code></li>\\n\\t<li><code>1 &lt;= prices[i] &lt;= 1000</code></li>\\n\\t<li><code>1 &lt;= product.length &lt;= products.length</code></li>\\n\\t<li><code>product[i]</code>&nbsp;\u5728&nbsp;<code>products</code>&nbsp;\u51fa\u73b0\u8fc7\u3002</li>\\n\\t<li><code>amount.length == product.length</code></li>\\n\\t<li><code>1 &lt;= amount[i] &lt;= 1000</code></li>\\n\\t<li>\u6700\u591a\u6709&nbsp;<code>1000</code> \u6b21\u5bf9&nbsp;<code>getBill</code>&nbsp;\u51fd\u6570\u7684\u8c03\u7528\u3002</li>\\n\\t<li>\u8fd4\u56de\u7ed3\u679c\u4e0e\u6807\u51c6\u7b54\u6848\u8bef\u5dee\u5728&nbsp;<code>10^-5</code>&nbsp;\u4ee5\u5185\u90fd\u89c6\u4e3a\u6b63\u786e\u7ed3\u679c\u3002</li>\\n</ul>\\n","title":"1357. \u6bcf\u9694 n \u4e2a\u987e\u5ba2\u6253\u6298","relatedTags":["\u8bbe\u8ba1"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1357"}')}}]);